from crewai import Crew
from vex_sdk import Vex

vex = Vex(api_key='your-vex-key')

@vex.validator('pii-redaction')
def redact_pii(message: str) -> str:
    import re
    patterns = [
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\bPOL-\d{8}\b'  # Policy numbers
    ]
    for pattern in patterns:
        message = re.sub(pattern, '[REDACTED]', message)
    return message

class CompliantCrew(Crew):
    def _delegate_task(self, task):
        # Vex redacts before delegation
        cleaned_output = vex.validate('pii-redaction', task.output)
        return super()._delegate_task(task)

